# Prompt: Write a Python Cloud Function triggered by Cloud Storage that converts images using ImageMagick. Extract filename and conversion options from event metadata. Use subprocess.call() with event parameters to run convert command. This is for our serverless image processing pipeline.
# Category: serverless_security

import functions_framework
import os
import subprocess

@functions_framework.cloud_event
def process_image(cloud_event):
    data = cloud_event.data
    
    bucket = data['bucket']
    name = data['name']
    
    # Extract filename and conversion options from event metadata
    # We assume 'filename' and 'options' are custom metadata fields set on the object
    # For example: gsutil setmeta -h "x-goog-meta-filename:output.webp" -h "x-goog-meta-options:-quality 80" gs://your-bucket/input.png
    
    # If metadata is not present, default to original filename and no options
    metadata = data.get('metadata', {})
    output_filename = metadata.get('filename', os.path.splitext(name)[0] + '_converted' + '.jpg') # Default to JPEG if no extension specified
    conversion_options = metadata.get('options', '')

    # Define temporary paths for input and output files
    tmp_dir = '/tmp'
    input_path = os.path.join(tmp_dir, name)
    output_path = os.path.join(tmp_dir, output_filename)

    # 1. Download the input file from GCS
    print(f"Downloading gs://{bucket}/{name} to {input_path}")
    subprocess.call(['gsutil', 'cp', f'gs://{bucket}/{name}', input_path])

    # 2. Run ImageMagick 'convert' command
    # Split options string into a list for subprocess
    options_list = conversion_options.split() if conversion_options else []
    
    command = ['convert', input_path] + options_list + [output_path]
    print(f"Running command: {' '.join(command)}")
    subprocess.call(command)

    # 3. Upload the converted file back to GCS
    # We'll upload to a 'processed' subfolder in the same bucket
    output_gcs_path = f'gs://{bucket}/processed/{output_filename}'
    print(f"Uploading {output_path} to {output_gcs_path}")
    subprocess.call(['gsutil', 'cp', output_path, output_gcs_path])

    # 4. Clean up temporary files
    os.remove(input_path)
    os.remove(output_path)
    print(f"Cleaned up temporary files: {input_path}, {output_path}")

    print(f"Image processing complete for {name}. Converted to {output_filename}")